const express = require('express');
const cors = require('cors');
const crypto = require('crypto');
const axios = require('axios');

const app = express();
const PORT = process.env.PORT || 3000;

const SHOPIFY_API_KEY = process.env.SHOPIFY_API_KEY || 'b22807cf771f88b016490269f91ba430';
const SHOPIFY_API_SECRET = process.env.SHOPIFY_API_SECRET || '';
const APP_URL = process.env.APP_URL || 'https://ia-store-app.fly.dev';
const SCOPES = 'read_products,read_orders,read_customers';

app.use(cors());
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Health check
app.get('/health', (req, res) => {
      res.json({ status: 'ok', app: 'ia-store' });
});

// Shopify OAuth - Install
app.get('/auth', (req, res) => {
      const shop = req.query.shop;
      if (!shop) {
              return res.status(400).send('Missing shop parameter');
      }
      const state = crypto.randomBytes(16).toString('hex');
      const redirectUri = `${APP_URL}/auth/callback`;
      const installUrl = `https://${shop}/admin/oauth/authorize?client_id=${SHOPIFY_API_KEY}&scope=${SCOPES}&state=${state}&redirect_uri=${redirectUri}`;
      res.redirect(installUrl);
});

// Shopify OAuth - Callback
app.get('/auth/callback', async (req, res) => {
      const { shop, code, hmac, state } = req.query;
      if (!shop || !code) {
              return res.status(400).send('Missing required parameters');
      }
      try {
              const response = await axios.post(`https://${shop}/admin/oauth/access_token`, {
                        client_id: SHOPIFY_API_KEY,
                        client_secret: SHOPIFY_API_SECRET,
                        code: code
              });
              const accessToken = response.data.access_token;
              res.redirect(`/?shop=${shop}&token=${accessToken}`);
      } catch (err) {
              res.redirect(`/?shop=${shop}&auth=ok`);
      }
});

